// The data layer is set once, per page, before any tags fire.
window.dataLayer = {
  page: {
    name:     "Product Detail",
    category: "Electronics",
    language: "en-IN"
  },
  product: {
    sku:      "ABC123",
    name:     "Wireless Headphones",
    price:    4999,
    currency: "INR"
  },
  user: {
    type:        "registered",
    loyaltyTier: "gold"
  }
};

// When something happens, push an event.
window.dataLayer.push({
  event:   "product:view",
  product: { sku: "ABC123" }
});
